#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;


vec2 uv1 = vec2(vUv.x-0.5,vUv.y-0.5);//*uAspect.xy;
float noise =  texture(sampler_noise_lq, vUv+rand_frame).x>0.5;

vec2 zz = (uv1 *uTexSize.xy + 10*vec2(q12,q13)) * reso;
zz =multiply(zz,mat2(_qa));

vec2 h1 = pow(2*abs(fract(zz))-1,3);
vUv.xy += h1*uTexSize.zw * .4/reso;

vec3 crisp = texture(sampler_main,vUv+uTexSize.zw*10*vec2(-q10,-q11));
ret = 1*multiply(crisp,rotmat)- .006* (uFrame%2) * noise;


ret += 0.003*length(h1)  * (1-6*lum(GetBlur3(vUv)));
//ret = max(ret, 0.06*length(h1));


  fragColor = ret;
}

_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

vec2 uv0 = vUv;
vUv = (vUv-0.5)*(1+vRadius*vRadius*0.5)*0.8+0.5;
uv1 = multiply((vUv-0.5)*uAspect.xy,mat2(q8,q9,-q9,q8));
rs = argo(uv1)+0.5;

vec3 struc = GetPixel(rs) * clamp01(ir0/kk-0);
//struc = pow(struc,0.8);
vec3 shine = struc*0;
radi0 = ir0/scale*uAspect.x/uAspect.y*0.7*mix(1/sqrt(q6), pow(q6,0.3),q5);
radi = radi0;
for (int n=0; n < anz; n++)
{
  radi = (1-(1.0*n/anz) ) * radi0;;
  shine += Get1(uv1*uAspect.yx*radi+0.5);
}
shine = clamp01(shine*2.1/anz-0.1);
shine = mix(shine, lum(shine), 0*clamp01(q14/3));
ret = shine + struc;

uv2 = vec2 (uv1.x*0.25+0.5,0.5+0.2*uv1.y);
ret = max(ret,clamp01(2-2*ir0/kk)*q15*(2*GetBlur1(uv2)+0.1)) ;
ret -= vec3(0,0,1); // MilkDrop 2077

  fragColor = ret;
}
